import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- 1. KURUMSAL VE TEKNİK AYARLAR ---st.set_page_config(    page_title="Focus AI | Master Coach ERP",     layout="wide",     initial_sidebar_state="expanded")# --- 2. GÜNCEL ÖSYM MÜFREDATI VE STRATEJİK SORU ANALİZİ (2021-2025) ---MÜFREDAT_STRATEJI = {    "TYT Matematik": {"Problemler": 12, "Sayılar": 3, "Geometri": 10, "Mantık/Kümeler": 2, "Fonksiyonlar": 1, "Rasyonel Sayılar": 1, "Üslü/Köklü": 2},    "AYT Matematik": {"Türev": 4, "İntegral": 4, "Trigonometri": 4, "Logaritma": 2, "Limit": 2, "Diziler": 1, "Polinomlar": 1},    "TYT Türkçe": {"Paragraf": 26, "Dil Bilgisi": 7, "Sözcük/Cümle Anlam": 7},    "AYT Edebiyat": {"Divan Edebiyatı": 5, "Cumhuriyet Dönemi": 4, "Şiir Bilgisi": 3, "Edebi Sanatlar": 2, "Halk Edebiyatı": 2},    "TYT Fen": {"Fizik": 7, "Kimya": 7, "Biyoloji": 6},    "AYT Fen": {"Sistemler (Bio)": 4, "Modern Fizik": 2, "Organik Kimya": 3, "Elektrik-Manyetizma": 3, "Enerji-Hız-Denge": 3}}REHBERLIK_SORULARI = {    "VAK Öğrenme Stilleri": ["Not tutmayı severim.", "Görsel şemalarla daha iyi anlarım.", "Ders dinlerken hareket etme ihtiyacı duyarım.", "Okuduğum metindeki grafikleri incelerim."],    "Sınav Kaygısı Ölçeği": ["Sınav anında ellerim titrer.", "Sınav öncesi uyuyamam.", "Unutma korkusu yaşarım.", "Zaman yetmeyecek diye paniklerim."],    "Odaklanma Testi": ["Ufak bir ses dikkatimi dağıtır.", "Bir işi bitirmeden diğerine geçerim.", "Uzun süre odaklanmak beni yorar."]}# --- 3. MERKEZİ HAFIZA SİSTEMİ ---for key in ['ogrenciler', 'program', 'video_odevler', 'test_sonuclari', 'soru_takip']:    if key not in st.session_state:        if key == 'ogrenciler':            st.session_state[key] = pd.DataFrame(columns=["Ad Soyad", "Alan", "Hedef Puan", "Veli Tel"])        elif key == 'program':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Ders", "Konu", "Soru Yükü", "Durum", "Tip"])        elif key == 'video_odevler':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Başlık", "Link", "Durum"])        elif key == 'test_sonuclari':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Test Adı", "Skor"])        elif key == 'soru_takip':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Ders", "D", "Y", "B"])        else:            st.session_state[key] = pd.DataFrame()# --- 4. NAVİGASYON (SIDEBAR) ---st.sidebar.title("🎯 Focus AI v8.5")st.sidebar.subheader("Bostanlı Çözüm VIP")role = st.sidebar.radio("SİSTEM PANELİ", ["👨‍🏫 KOÇLUK & YÖNETİM", "🎓 ÖĞRENCİ & ANALİZ"])ogrenci_listesi = st.session_state.ogrenciler["Ad Soyad"].tolist() if not st.session_state.ogrenciler.empty else ["Öğrenci Kaydı Yok"]# ==========================================# 👨‍🏫 MODÜL 1: KOÇLUK & YÖNETİM (ADMIN)# ==========================================if role == "👨‍🏫 KOÇLUK & YÖNETİM":    st.title("🏛️ Master Coach Operasyon Merkezi")    tabs = st.tabs(["👤 Kayıt & Rehber", "📋 Stratejik Planlama", "📺 Video Gönder", "🧠 Rehberlik Analizi", "📊 Başarı Radarı"])    with tabs[0]: # KAYIT        st.subheader("👤 Öğrenci ve Veli Tanımlama")        with st.form("kayit_f"):            c1, c2, c3 = st.columns(3)            n_ad = c1.text_input("Öğrenci Ad Soyad")            n_alan = c2.selectbox("Alan", ["Sayısal", "EA", "Sözel"])            n_h_p = c3.number_input("Hedef Puan", 200, 500, value=450)            n_tel = c1.text_input("Veli WhatsApp (905...)")            if st.form_submit_button("Sisteme Kaydet"):                yeni_o = pd.DataFrame([[n_ad, n_alan, n_h_p, n_tel]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_o], ignore_index=True)                st.success(f"{n_ad} Kaydedildi!")                st.rerun()        st.dataframe(st.session_state.ogrenciler, use_container_width=True)    with tabs[1]: # PLANLAMA        st.subheader("🛠️ TYT-AYT Konu ve Soru Yükü Atama")        with st.form("odev_f"):            c1, c2, c3 = st.columns(3)            o_at = c1.selectbox("Öğrenci", ogrenci_listesi, key="o1")            d_at = c2.selectbox("Ders", list(MÜFREDAT_STRATEJI.keys()))            k_at = c3.multiselect("Konular", list(MÜFREDAT_STRATEJI[d_at].keys()))            s_tip = st.radio("Sınav Tipi", ["TYT", "AYT"], horizontal=True)            if st.form_submit_button("Yol Haritasına Ekle"):                for k in k_at:                    s_y = MÜFREDAT_STRATEJI[d_at][k]                    yeni_p = pd.DataFrame([[o_at, d_at, k, s_y, "Bekliyor", s_tip]], columns=st.session_state.program.columns)                    st.session_state.program = pd.concat([st.session_state.program, yeni_p], ignore_index=True)                st.success("Görevler başarıyla atandı!")    with tabs[2]: # VİDEO GÖNDER        st.subheader("📺 YouTube Playlist/Video Gönderimi")        with st.form("v_f"):            v_o = st.selectbox("Hedef Öğrenci", ogrenci_listesi, key="v1")            v_b = st.text_input("Video Başlığı")            v_u = st.text_input("YouTube URL")            if st.form_submit_button("Videoyu Gönder"):                yeni_v = pd.DataFrame([[v_o, v_b, v_u, "İzlenmedi"]], columns=st.session_state.video_odevler.columns)                st.session_state.video_odevler = pd.concat([st.session_state.video_odevler, yeni_v], ignore_index=True)                st.success("Video öğrenciye iletildi!")    with tabs[3]: # REHBERLİK ANALİZİ        st.subheader("🧠 Psikolojik ve Rehberlik Analizleri")        st.dataframe(st.session_state.test_sonuclari, use_container_width=True)        if not st.session_state.test_sonuclari.empty:            fig_pdr = px.bar(st.session_state.test_sonuclari, x="Öğrenci", y="Skor", color="Test Adı", barmode="group")            st.plotly_chart(fig_pdr, use_container_width=True)    with tabs[4]: # RADAR        st.subheader("🕸️ Genel Gelişim Radarı")        fig_r = go.Figure(data=go.Scatterpolar(r=[80, 75, 90, 65, 85], theta=['Akademik', 'Odak', 'Hız', 'Mental', 'Düzen'], fill='toself'))        st.plotly_chart(fig_r, use_container_width=True)# ==========================================# 🎓 MODÜL 2: ÖĞRENCİ & ANALİZ (USER)# ==========================================else:    st.title("🎓 Focus AI: Öğrenci ve Başarı Paneli")    otabs = st.tabs(["🧮 Net & Hedef Hesaplama", "📅 Çalışma Programım", "📺 Videolarım", "🧠 Rehberlik Testleri", "🎯 Soru Girişi"])    with otabs[0]: # NET HESAPLAMA        st.subheader("🔍 Kaç Net Lazım? (Akıllı Hesaplayıcı)")        c1, c2 = st.columns(2)        with c1:            t_mat = st.number_input("TYT Mat", 0.0, 40.0, step=1.25)            t_tur = st.number_input("TYT Tür", 0.0, 40.0, step=1.25)            obp = st.number_input("OBP", 0.0, 100.0, value=85.0)        with c2:            a_mat = st.number_input("AYT Mat", 0.0, 40.0, step=1.25)            a_fen = st.number_input("AYT Fen/Ed", 0.0, 40.0, step=1.25)                tahmini_p = ( (t_mat+t_tur)*1.3 + (a_mat+a_fen)*3.0 ) + (obp*0.6) + 150        st.header(f"📊 Tahmini Puanın: {tahmini_p:.2f}")                if not st.session_state.ogrenciler.empty:            hed_p = st.session_state.ogrenciler.iloc[0]["Hedef Puan"]            fark = hed_p - tahmini_p            if fark > 0:                st.warning(f"🎯 Hedefine ulaşmak için **{fark:.2f}** puan (Yaklaşık {fark/3:.1f} AYT Neti) daha lazım!")            else:                st.balloons(); st.success("Şu anki netlerinle hedeftesin!")    with otabs[1]: # PROGRAM        st.subheader("📅 ÖSYM Konu Listem")        for i, r in st.session_state.program.iterrows():            if r["Durum"] == "Bekliyor":                c_p1, c_p2 = st.columns([4, 1])                c_p1.info(f"📌 **{r['Ders']}** | {r['Konu']} ({r['Tip']}) - Soru Değeri: **{r['Soru Yükü']}**")                if c_p2.button("Bitti ✅", key=f"prog_{i}"):                    st.session_state.program.at[i, "Durum"] = "Tamamlandı"; st.rerun()    with otabs[2]: # VİDEO        st.subheader("📺 Sana Atanan Videolar")        for i, r in st.session_state.video_odevler.iterrows():            st.success(f"🎥 {r['Başlık']}")            st.link_button("İzle", r['Link'])    with otabs[3]: # REHBERLİK        st.subheader("🧠 Rehberlik Testini Çöz")        t_sec = st.selectbox("Test Seç", list(REHBERLIK_SORULARI.keys()))        skor = 0        with st.form("pdr_f"):            for q in REHBERLIK_SORULARI[t_sec]:                ans = st.select_slider(q, options=["Hiç", "Az", "Orta", "Çok", "Tamamen"], value="Orta")                puanlar = {"Hiç":0, "Az":5, "Orta":10, "Çok":15, "Tamamen":20}; skor += puanlar[ans]            o_onay = st.selectbox("İsmin", ogrenci_listesi)            if st.form_submit_button("Testi Gönder"):                yeni_t = pd.DataFrame([[datetime.now().strftime("%d/%m"), o_onay, t_sec, skor]], columns=st.session_state.test_sonuclari.columns)                st.session_state.test_sonuclari = pd.concat([st.session_state.test_sonuclari, yeni_t], ignore_index=True)                st.success("Sonuç iletildi!")    with otabs[4]: # SORU GİRİŞİ        st.subheader("🎯 Günlük Soru Takibi")        with st.form("soru_f"):            s_d = st.selectbox("Ders", ["Matematik", "Türkçe", "Fen", "Sosyal"])            c_s1, c_s2, c_s3 = st.columns(3)            sd = c_s1.number_input("Doğru", 0); sy = c_s2.number_input("Yanlış", 0); sb = c_s3.number_input("Boş", 0)            if st.form_submit_button("Soru Verisini Kaydet"):                yeni_s = pd.DataFrame([[datetime.now().date(), "Öğrenci", s_d, sd, sy, sb]], columns=st.session_state.soru_takip.columns)                st.session_state.soru_takip = pd.concat([st.session_state.soru_takip, yeni_s], ignore_index=True)                st.success("Veri kaydedildi!")